// 2.5D Sprite + Pseudo-3D Depth Extrusion Generator
function Pseudo3DModel({ url, depthUrl }: { url: string, depthUrl?: string }) {
  const textures = useTexture(depthUrl ? [url, depthUrl] : [url]);
  const texture = textures[0];
  const depthTexture = depthUrl ? textures[1] : null;

  const aspect = texture.image.width / texture.image.height;
  const tess = depthUrl ? 256 : 1;
  const outScale = 0.5; // Controlled puff

  return (
    <group position={[0, Math.max(0.5, 1 / aspect), 0]}>
      {/* Front Face: Displaces outward towards the camera */}
      <mesh castShadow receiveShadow position={[0, 0, 0.01]}>
        <planeGeometry args={[2 * aspect, 2, tess, tess]} />
        <meshStandardMaterial 
           map={texture} 
           displacementMap={depthTexture}
           displacementScale={outScale}
           transparent 
           alphaTest={0.4} 
        />
      </mesh>
      
      {/* Back Face: Displaces outward away from the camera, sealing the volume! */}
      <mesh castShadow receiveShadow position={[0, 0, -0.01]} rotation={[0, Math.PI, 0]}>
        <planeGeometry args={[2 * aspect, 2, tess, tess]} />
        <meshStandardMaterial 
           map={texture} 
           displacementMap={depthTexture}
           displacementScale={outScale}
           transparent 
           alphaTest={0.4} 
        />
      </mesh>
    </group>
  );
}

