  chair: "https://vazxmixizvqrvxnwfczt.supabase.co/storage/v1/object/public/models/chair/model.gltf",
  bed: "https://vazxmixizvqrvxnwfczt.supabase.co/storage/v1/object/public/models/bed/model.gltf",
