function getProceduralModel(asset: string) {
  const key = asset.toLowerCase();
  if (key.includes("chair")) return <ProceduralChair />;
  if (key.includes("bed")) return <ProceduralBed />;
  if (key.includes("table")) return <ProceduralTable />;
  if (key.includes("couch") || key.includes("sofa")) return <ProceduralCouch />;
  if (key.includes("plant") || key.includes("vase")) return <ProceduralPlant />;
  
  // Fallback Cube
  return (
    <mesh castShadow position={[0, 0, 0]}>
      <boxGeometry args={[0.8, 0.8, 0.8]} />
      <meshStandardMaterial color="#6366f1" />
    </mesh>
  );
}

export default function NLPObject({
  data,
  index,
  isSelected,
  onSelect,
}: NLPObjectProps) {
  const groupRef = useRef<THREE.Group>(null);
  
  // Decide the visual mesh: Actual 2D-to-3D Extracted Furniture, or Fallback Procedural
  const modelContent = data.cutout_url ? (
    <Suspense fallback={getProceduralModel(data.asset)}>
      <Pseudo3DModel url={data.cutout_url} depthUrl={data.depth_url} />
    </Suspense>
  ) : (
    getProceduralModel(data.asset)
  );

  const innerGroup = (
    <group
      position={data.position}
      scale={data.scale}
      ref={groupRef}
      onClick={(e) => {
        e.stopPropagation();
        onSelect(data.id);
      }}
      name={data.id}
    >
      {modelContent}

      <Html position={[0, 1.2, 0]} center distanceFactor={6} zIndexRange={[10, 0]}>
        <div className="nlp-label" style={{ 
          background: isSelected ? "#6366f1" : "rgba(0,0,0,0.6)",
          color: "white", padding: "4px 8px", borderRadius: "4px", fontSize: "14px",
          border: isSelected ? "2px solid white" : "none"
        }}>
          {data.asset}
        </div>
      </Html>

      {isSelected && (
        <boxHelper args={[new THREE.Mesh(new THREE.BoxGeometry(2.5, 2.0, 2.5)), 0x6366f1]} />
      )}
    </group>
  );

  // If selected, wrap perfectly in PivotControls to allow easy XZ-plane dragging
  return isSelected ? (
    <PivotControls
      activeAxes={[true, false, true]} // Hide Y axis, restrict drag to floor
      scale={2.5}
      depthTest={false}
      lineWidth={5}
    >
      {innerGroup}
    </PivotControls>
  ) : (
    innerGroup
  );
}
