"use client";

import { useSearchParams } from "next/navigation";
import { useState, Suspense, useCallback, useEffect } from "react";
import { Canvas } from "@react-three/fiber";
import styles from "./scene.module.css";
import "./scene.css";
import SceneViewer from "./components/SceneViewer";
import LoadingSpinner from "./components/LoadingSpinner";
import { NLPObjectData } from "./components/NLPObject";

/* -------------------------------------------------------------------
   Local NLP keyword → position/scale lookup table.
   Used as fallback when the backend /nlp-place isn't wired yet.
   ------------------------------------------------------------------- */
const NLP_POSITION_TABLE: Record<
  string,
  { position: [number, number, number]; scale: [number, number, number] }
> = {
  bookshelf: { position: [3, 0.9, 0], scale: [1.2, 1.8, 0.4] },
  table: { position: [0, 0.4, 3], scale: [1.5, 0.8, 1] },
  desk: { position: [-3, 0.45, 0], scale: [1.4, 0.9, 0.8] },
  chair: { position: [1.5, 0.5, -2], scale: [0.6, 1, 0.6] },
  lamp: { position: [2, 0.75, 2], scale: [0.3, 1.5, 0.3] },
  sofa: { position: [-2, 0.5, -2.5], scale: [2, 0.8, 1] },
  couch: { position: [-2, 0.5, -2.5], scale: [2, 0.8, 1] },
  cabinet: { position: [4, 0.8, -1], scale: [1, 1.6, 0.5] },
  bed: { position: [0, 0.4, -4], scale: [2, 0.6, 2.5] },
  plant: { position: [-3.5, 0.6, 3], scale: [0.5, 1.2, 0.5] },
  vase: { position: [1, 0.4, 1], scale: [0.3, 0.8, 0.3] },
  rug: { position: [0, 0.02, 0], scale: [3, 1, 2] },
  shelf: { position: [4, 1.2, 2], scale: [1, 0.3, 0.4] },
  pillar: { position: [-4, 1.5, -3], scale: [0.4, 3, 0.4] },
  globe: { position: [3, 1.2, -3], scale: [0.6, 0.6, 0.6] },
};

function extractAsset(prompt: string): string {
  const lower = prompt.toLowerCase();
  for (const kw of Object.keys(NLP_POSITION_TABLE)) {
    if (lower.includes(kw)) return kw;
  }
  const words = lower.trim().split(/\s+/);
  return words[words.length - 1];
}

/* -------------------------------------------------------------------
   Scene content (inside Suspense for useSearchParams)
   ------------------------------------------------------------------- */
function SceneContent() {
  const searchParams = useSearchParams();
  /* Person D uses ?url=, Person C used ?model=  — support both */
  const modelUrl = searchParams.get("url") || searchParams.get("model") || null;
  const isDemo = !modelUrl || modelUrl === "/test.glb";

  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [nlpObjects, setNlpObjects] = useState<NLPObjectData[]>([]);
  const [arBgImage, setArBgImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState("");
  const [status, setStatus] = useState<"idle" | "loading" | "success">("idle");
  const [message, setMessage] = useState("");
  const [toast, setToast] = useState<string | null>(null);
  const [toastFading, setToastFading] = useState(false);

  useEffect(() => {
    if (searchParams.get("mode") === "ar") {
      const bg = sessionStorage.getItem("ar_bg");
      const objs = sessionStorage.getItem("ar_objects");
      if (bg) setArBgImage(bg);
      if (objs) {
        try {
          const parsed = JSON.parse(objs);
          setNlpObjects(parsed);
        } catch (e) {
          console.error("Failed to parse AR objects", e);
        }
      }
    }
  }, [searchParams]);

  const showToast = useCallback((msg: string) => {
    setToastFading(false);
    setToast(msg);
    setTimeout(() => setToastFading(true), 2200);
    setTimeout(() => setToast(null), 2600);
  }, []);

  const handlePlaceObject = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!prompt) return;

    setStatus("loading");
    setMessage("");

    let asset: string;
    let position: [number, number, number];
    let scale: [number, number, number];

    try {
      /* Try Person D's Next.js API route first (which can proxy to backend) */
      const res = await fetch("/api/nlp-place", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ prompt }),
      });
      const data = await res.json();

      if (data.status === "ok") {
        setStatus("success");
        setMessage(data.message);

        /* If backend returns asset/position/scale, use them */
        if (data.asset && data.position) {
          asset = data.asset;
          position = data.position;
          scale = data.scale || [1, 1, 1];
        } else {
          /* Fallback: extract from prompt + use local lookup */
          asset = extractAsset(prompt);
          const entry = NLP_POSITION_TABLE[asset] || {
            position: [(Math.random() - 0.5) * 6, 0.5, (Math.random() - 0.5) * 6] as [number, number, number],
            scale: [1, 1, 1] as [number, number, number],
          };
          position = entry.position;
          scale = entry.scale;
        }
      } else {
        throw new Error("Backend returned error");
      }
    } catch {
      /* Full fallback — local keyword lookup */
      asset = extractAsset(prompt);
      const entry = NLP_POSITION_TABLE[asset] || {
        position: [(Math.random() - 0.5) * 6, 0.5, (Math.random() - 0.5) * 6] as [number, number, number],
        scale: [1, 1, 1] as [number, number, number],
      };
      position = entry.position;
      scale = entry.scale;
      setStatus("success");
      setMessage(`Added ${asset} to scene (local mode)`);
    }

    const newObj: NLPObjectData = {
      id: `nlp-${Date.now()}-${asset}`,
      asset,
      position,
      scale,
    };

    setNlpObjects((prev) => [...prev, newObj]);
    showToast(`✓ Added "${asset}" to scene`);
    setPrompt("");
  };

  return (
    <div className="scene-wrapper">
      {/* ---------- Top Bar (Person D's toolbar, upgraded) ---------- */}
      <div className="scene-topbar">
        <div className="scene-topbar-title">
          <span className="dot" />
          Spac3D — {isDemo ? "Demo Scene" : "Reconstructed Scene"}
        </div>
        <a href="/" className="scene-topbar-back">
          ← Upload
        </a>
      </div>

      {/* ---------- Controls Hint ---------- */}
      <div className="controls-hint">
        <span className="hint-chip"><kbd>Drag</kbd> Rotate</span>
        <span className="hint-chip"><kbd>Scroll</kbd> Zoom</span>
        <span className="hint-chip"><kbd>Click</kbd> Select object</span>
        <span className="hint-chip"><kbd>R-Click</kbd> Pan</span>
      </div>

      {/* ---------- Selection Badge ---------- */}
      {selectedId && (
        <div className="selection-badge">
          Selected: <strong>{selectedId}</strong>
          <button
            className="deselect-btn"
            onClick={() => setSelectedId(null)}
            title="Deselect"
          >
            ✕
          </button>
        </div>
      )}

      {/* ---------- 3D Canvas ---------- */}
      <Canvas
        shadows
        camera={{ position: [6, 5, 8], fov: 50, near: 0.1, far: 200 }}
        style={{ width: "100%", height: "100%" }}
        gl={{ antialias: true, toneMapping: 3 /* ACESFilmic */ }}
      >
        <Suspense fallback={null}>
          <SceneViewer
            modelUrl={isDemo ? null : modelUrl}
            arBgImage={arBgImage}
            nlpObjects={nlpObjects}
            selectedId={selectedId}
            onSelect={setSelectedId}
          />
        </Suspense>
      </Canvas>

      {/* ---------- NLP Input Bar (Person D's form, upgraded styling) ---------- */}
      <div className="nlp-bar">
        <form onSubmit={handlePlaceObject} style={{ display: "flex", gap: "0.75rem", width: "100%" }}>
          <input
            className="nlp-input"
            type="text"
            placeholder='Add an object… e.g. "place a bookshelf near the window"'
            value={prompt}
            onChange={(e) => setPrompt(e.target.value)}
            disabled={status === "loading"}
            id="nlp-input"
          />
          <button
            type="submit"
            className="nlp-submit"
            disabled={!prompt || status === "loading"}
            id="nlp-submit"
          >
            {status === "loading" ? "Processing…" : "Add Object"}
          </button>
        </form>
      </div>

      {/* ---------- Status Message ---------- */}
      {message && (
        <div style={{
          position: "fixed", bottom: "5.5rem", left: "50%", transform: "translateX(-50%)",
          zIndex: 45, fontFamily: "'Outfit', sans-serif", fontSize: "0.8rem",
          color: status === "success" ? "#34d399" : "#f87171",
        }}>
          {message}
        </div>
      )}

      {/* ---------- Toast ---------- */}
      {toast && (
        <div className={`toast${toastFading ? " fade-out" : ""}`}>{toast}</div>
      )}
    </div>
  );
}

/* -------------------------------------------------------------------
   Page wrapper — Suspense boundary around useSearchParams
   ------------------------------------------------------------------- */
export default function Scene() {
  return (
    <Suspense fallback={<LoadingSpinner />}>
      <SceneContent />
    </Suspense>
  );
}
