"use client";

import React, { useRef, useState, useCallback, useEffect } from "react";
import { useFrame } from "@react-three/fiber";
import {
  OrbitControls,
  TransformControls,
  Grid,
  useTexture,
} from "@react-three/drei";
import * as THREE from "three";
import GLBModel from "./GLBModel";
import NLPObject, { NLPObjectData } from "./NLPObject";

/* -------------------------------------------------------------------
   SceneViewer — the root 3D scene component rendered inside <Canvas>.
   Handles:
     • Demo mode (rotating box) vs Model mode (.glb URL)
     • Object selection + TransformControls
     • NLP-placed objects as primitives
     • Floor grid for spatial grounding
     • OrbitControls ↔ TransformControls conflict resolution
   ------------------------------------------------------------------- */

interface SceneViewerProps {
  modelUrl: string | null;
  arBgImage?: string | null;
  nlpObjects: NLPObjectData[];
  selectedId: string | null;
  onSelect: (id: string | null) => void;
}

/* ---------- Demo box shown when no .glb is loaded ---------- */
function DemoBox({
  isSelected,
  onSelect,
}: {
  isSelected: boolean;
  onSelect: () => void;
}) {
  const ref = useRef<THREE.Mesh>(null);

  useFrame((_, delta) => {
    if (ref.current && !isSelected) {
      ref.current.rotation.x += delta * 0.4;
      ref.current.rotation.y += delta * 0.6;
    }
  });

  return (
    <mesh
      ref={ref}
      position={[0, 1, 0]}
      onClick={(e) => {
        e.stopPropagation();
        onSelect();
      }}
      castShadow
    >
      <boxGeometry args={[1.4, 1.4, 1.4]} />
      <meshStandardMaterial
        color="#6366f1"
        emissive={isSelected ? "#6366f1" : "#000000"}
        emissiveIntensity={isSelected ? 0.5 : 0}
        roughness={0.25}
        metalness={0.35}
      />
    </mesh>
  );
}

/* ---------- A second demo object to make the scene interactive ---------- */
function DemoSphere({
  isSelected,
  onSelect,
}: {
  isSelected: boolean;
  onSelect: () => void;
}) {
  const ref = useRef<THREE.Mesh>(null);

  useFrame((state) => {
    if (ref.current && !isSelected) {
      ref.current.position.y =
        1 + Math.sin(state.clock.elapsedTime * 1.5) * 0.15;
    }
  });

  return (
    <mesh
      ref={ref}
      position={[2.5, 1, -1]}
      onClick={(e) => {
        e.stopPropagation();
        onSelect();
      }}
      castShadow
    >
      <sphereGeometry args={[0.6, 32, 32]} />
      <meshStandardMaterial
        color="#8b5cf6"
        emissive={isSelected ? "#8b5cf6" : "#000000"}
        emissiveIntensity={isSelected ? 0.5 : 0}
        roughness={0.2}
        metalness={0.3}
      />
    </mesh>
  );
}

function DemoCylinder({
  isSelected,
  onSelect,
}: {
  isSelected: boolean;
  onSelect: () => void;
}) {
  return (
    <mesh
      position={[-2, 0.75, 1.5]}
      onClick={(e) => {
        e.stopPropagation();
        onSelect();
      }}
      castShadow
    >
      <cylinderGeometry args={[0.4, 0.4, 1.5, 24]} />
      <meshStandardMaterial
        color="#14b8a6"
        emissive={isSelected ? "#14b8a6" : "#000000"}
        emissiveIntensity={isSelected ? 0.5 : 0}
        roughness={0.3}
        metalness={0.2}
      />
    </mesh>
  );
}

function ARBackground({ url }: { url: string }) {
  const texture = useTexture(url);
  texture.colorSpace = THREE.SRGBColorSpace;
  return (
    <mesh position={[0, 0, -5]} scale={[24, 24, 1]}>
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial map={texture} depthTest={false} depthWrite={false} toneMapped={false} />
    </mesh>
  );
}

export default function SceneViewer({
  modelUrl,
  arBgImage,
  nlpObjects,
  selectedId,
  onSelect,
}: SceneViewerProps) {
  const orbitRef = useRef<any>(null); // eslint-disable-line @typescript-eslint/no-explicit-any
  const transformRef = useRef<any>(null); // eslint-disable-line @typescript-eslint/no-explicit-any
  const [isDragging, setIsDragging] = useState(false);

  /* Find the selected Three.js object in the scene for TransformControls */
  const selectedObjRef = useRef<THREE.Object3D | null>(null);
  const sceneGroupRef = useRef<THREE.Group>(null);

  /* Sync selected object ref when selection changes */
  useEffect(() => {
    if (!selectedId || !sceneGroupRef.current) {
      selectedObjRef.current = null;
      return;
    }
    let found: THREE.Object3D | null = null;
    sceneGroupRef.current.traverse((child) => {
      if (child.name === selectedId || (child as THREE.Mesh).isMesh && child.name === selectedId) {
        found = child;
      }
    });
    selectedObjRef.current = found;
  }, [selectedId]);

  /* Disable OrbitControls while dragging TransformControls */
  useEffect(() => {
    const tc = transformRef.current;
    if (!tc) return;

    const onDragStart = () => setIsDragging(true);
    const onDragEnd = () => setIsDragging(false);

    tc.addEventListener("dragging-changed", (event: { value: boolean }) => {
      if (orbitRef.current) {
        orbitRef.current.enabled = !event.value;
      }
      if (event.value) onDragStart();
      else onDragEnd();
    });
  }, [selectedId]);

  /* Click on empty space → deselect */
  const handlePointerMissed = useCallback(() => {
    onSelect(null);
  }, [onSelect]);

  const isDemo = !modelUrl;

  return (
    <>
      {/* ---------- Lighting ---------- */}
      <ambientLight intensity={0.4} color="#b4c6ef" />
      <directionalLight
        position={[8, 12, 5]}
        intensity={1.2}
        castShadow
        shadow-mapSize-width={2048}
        shadow-mapSize-height={2048}
        shadow-camera-far={50}
        shadow-camera-left={-15}
        shadow-camera-right={15}
        shadow-camera-top={15}
        shadow-camera-bottom={-15}
      />
      <directionalLight position={[-5, 8, -3]} intensity={0.3} color="#a5b4fc" />
      <hemisphereLight
        args={["#6366f1", "#0a0b10", 0.3]}
      />

      {/* ---------- Controls ---------- */}
      <OrbitControls
        ref={orbitRef}
        makeDefault
        enabled={!isDragging}
        enableDamping
        dampingFactor={0.08}
        minDistance={3}
        maxDistance={20}
        minAzimuthAngle={-0.2}
        maxAzimuthAngle={0.2}
        minPolarAngle={Math.PI / 2 - 0.2}
        maxPolarAngle={Math.PI / 2 + 0.2}
        enablePan={false}
      />

      {/* TransformControls removed in favor of integrated PivotControls in NLPObject */}

      {/* ---------- Scene content ---------- */}
      <group ref={sceneGroupRef} onPointerMissed={handlePointerMissed}>
        {/* AR Plane Background (always behind) */}
        {arBgImage && <ARBackground url={arBgImage} />}

        {/* Floor grid */}
        <Grid
          args={[30, 30]}
          position={[0, -0.01, 0]}
          cellSize={1}
          cellThickness={0.6}
          cellColor="#1e293b"
          sectionSize={5}
          sectionThickness={1.2}
          sectionColor="#334155"
          fadeDistance={30}
          fadeStrength={1.5}
          infiniteGrid
        />

        {/* Floor plane for shadow catching */}
        <mesh
          rotation={[-Math.PI / 2, 0, 0]}
          position={[0, -0.02, 0]}
          receiveShadow
        >
          <planeGeometry args={[60, 60]} />
          <shadowMaterial transparent opacity={0.35} />
        </mesh>

        {/* Demo objects (when no .glb loaded) */}
        {isDemo && !arBgImage && (
          <>
            <DemoBox
              isSelected={selectedId === "demo-box"}
              onSelect={() => onSelect("demo-box")}
            />
            <DemoSphere
              isSelected={selectedId === "demo-sphere"}
              onSelect={() => onSelect("demo-sphere")}
            />
            <DemoCylinder
              isSelected={selectedId === "demo-cylinder"}
              onSelect={() => onSelect("demo-cylinder")}
            />
          </>
        )}

        {/* Loaded .glb model */}
        {modelUrl && (
          <GLBModel
            url={modelUrl}
            selectedId={selectedId}
            onSelect={(name) => onSelect(name)}
          />
        )}

        {/* NLP-placed objects */}
        {nlpObjects.map((obj, i) => (
          <NLPObject
            key={obj.id}
            data={obj}
            index={i}
            isSelected={selectedId === obj.id}
            onSelect={(id) => onSelect(id)}
          />
        ))}
      </group>
    </>
  );
}
