"use client";

import React, { useMemo, useCallback } from "react";
import { useGLTF } from "@react-three/drei";
import * as THREE from "three";

/* -------------------------------------------------------------------
   GLBModel — loads a .glb from useGLTF, iterates over all meshes,
   wraps each in a <group> with onClick to support per-object selection.
   Applies a Y-up correction (Open3D exports Z-up) by rotating -90° on X.
   ------------------------------------------------------------------- */

interface GLBModelProps {
  url: string;
  selectedId: string | null;
  onSelect: (name: string) => void;
  /** Set to true if the .glb is already Y-up (e.g., Sketchfab exports) */
  yUp?: boolean;
}

export default function GLBModel({
  url,
  selectedId,
  onSelect,
  yUp = false,
}: GLBModelProps) {
  const gltf = useGLTF(url);

  /* Collect all mesh nodes from the loaded scene */
  const meshNodes = useMemo(() => {
    const nodes: THREE.Mesh[] = [];
    gltf.scene.traverse((child) => {
      if ((child as THREE.Mesh).isMesh) {
        nodes.push(child as THREE.Mesh);
      }
    });
    return nodes;
  }, [gltf.scene]);

  const handleClick = useCallback(
    (e: { stopPropagation: () => void }, name: string) => {
      e.stopPropagation();
      onSelect(name);
    },
    [onSelect]
  );

  return (
    <group rotation={yUp ? [0, 0, 0] : [-Math.PI / 2, 0, 0]}>
      {meshNodes.map((mesh, i) => {
        const id = mesh.name || `mesh-${i}`;
        const isSelected = selectedId === id;

        /* Clone the material so we can set emissive per-instance */
        const mat = (mesh.material as THREE.MeshStandardMaterial).clone?.()
          ? (mesh.material as THREE.MeshStandardMaterial).clone()
          : new THREE.MeshStandardMaterial({ color: "#888" });

        if (isSelected) {
          mat.emissive = new THREE.Color("#6366f1");
          mat.emissiveIntensity = 0.55;
        } else {
          mat.emissiveIntensity = 0;
        }

        return (
          <group key={id}>
            <mesh
              name={id}
              geometry={mesh.geometry}
              material={mat}
              position={mesh.getWorldPosition(new THREE.Vector3())}
              quaternion={mesh.getWorldQuaternion(new THREE.Quaternion())}
              scale={mesh.getWorldScale(new THREE.Vector3())}
              onClick={(e) => handleClick(e, id)}
              castShadow
              receiveShadow
            />
          </group>
        );
      })}
    </group>
  );
}
